CREATE ROLE admin;
CREATE ROLE cliente;

GRANT ALL PRIVILEGES ON ecoruta.* TO admin;
GRANT SELECT, INSERT ON ecoruta.* TO cliente;

CREATE USER 'admin1'@'localhost' IDENTIFIED BY '1234';
CREATE USER 'user1'@'localhost' IDENTIFIED BY '1234';

GRANT admin TO 'admin1'@'localhost';
GRANT cliente TO 'user1'@'localhost';

CREATE VIEW vista_reservas AS
SELECT t.nombre, e.nombre AS experiencia, r.fecha
FROM reserva r
JOIN turista t ON r.turista_id = t.id
JOIN experiencia e ON r.experiencia_id = e.id;

CREATE VIEW vista_pagos AS
SELECT p.monto, p.metodo, r.id
FROM pago p
JOIN reserva r ON p.reserva_id = r.id;

CREATE VIEW vista_valoraciones AS
SELECT v.comentario, v.puntuacion, t.nombre
FROM valoracion v
JOIN turista t ON v.turista_id = t.id;

CREATE VIEW vista_turistas AS SELECT * FROM turista;
CREATE VIEW vista_experiencias AS SELECT * FROM experiencia;

